"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDocs,
  orderBy,
  query,
  serverTimestamp,
} from "firebase/firestore";
import { signOut } from "firebase/auth";
import { auth, db } from "@/lib/firebase";

type NewsItem = {
  id: string;
  title: string;
  summary: string;
  content: string;
  category: string;
  imageUrl?: string;
  published?: boolean;
  createdAt?: string;
};

type CategoryItem = {
  id: string;
  name: string;
  slug: string;
};

const getDriveDirectLink = (url: string) => {
  const match = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/id=([^&]+)/);
  if (!match) return "";
  return `https://drive.google.com/uc?export=view&id=${match[1]}`;
};

export default function AdminDashboardPage() {
  const router = useRouter();
  const [news, setNews] = useState<NewsItem[]>([]);
  const [categories, setCategories] = useState<CategoryItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const [title, setTitle] = useState("");
  const [summary, setSummary] = useState("");
  const [content, setContent] = useState("");
  const [category, setCategory] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [categoryName, setCategoryName] = useState("");

  const categoryOptions = useMemo(
    () => categories.map((item) => ({ value: item.slug, label: item.name })),
    [categories]
  );

  const loadNews = async () => {
    const snapshot = await getDocs(
      query(collection(db, "news"), orderBy("createdAt", "desc"))
    );
    const items = snapshot.docs.map((docRef) => ({
      id: docRef.id,
      ...(docRef.data() as Omit<NewsItem, "id">),
    }));
    setNews(items);
  };

  const loadCategories = async () => {
    const snapshot = await getDocs(
      query(collection(db, "categories"), orderBy("name", "asc"))
    );
    const items = snapshot.docs.map((docRef) => ({
      id: docRef.id,
      ...(docRef.data() as Omit<CategoryItem, "id">),
    }));
    setCategories(items);
  };

  useEffect(() => {
    if (!auth.currentUser) {
      router.push("/admin/login");
      return;
    }
    loadNews().catch(() => setError("Failed to load news."));
    loadCategories().catch(() => setError("Failed to load categories."));
  }, [router]);

  const handleLogout = async () => {
    await signOut(auth);
    router.push("/admin/login");
  };

  const handleCreateNews = async (event: React.FormEvent) => {
    event.preventDefault();
    setError("");
    if (!title.trim() || !summary.trim() || !content.trim() || !category.trim()) {
      setError("Title, summary, content, and category are required.");
      return;
    }
    setLoading(true);
    try {
      await addDoc(collection(db, "news"), {
        title: title.trim(),
        summary: summary.trim(),
        content: content.trim(),
        category: category.trim(),
        imageUrl: imageUrl.trim(),
        published: true,
        createdAt: serverTimestamp(),
      });
      setTitle("");
      setSummary("");
      setContent("");
      setCategory("");
      setImageUrl("");
      await loadNews();
    } catch (err: any) {
      setError(err?.message || "Failed to create news.");
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteNews = async (id: string) => {
    await deleteDoc(doc(db, "news", id));
    await loadNews();
  };

  const handleCreateCategory = async () => {
    setError("");
    if (!categoryName.trim()) {
      setError("Category name is required.");
      return;
    }
    const slug = categoryName.trim().toLowerCase().replace(/\s+/g, "-");
    await addDoc(collection(db, "categories"), {
      name: categoryName.trim(),
      slug,
      createdAt: serverTimestamp(),
    });
    setCategoryName("");
    await loadCategories();
  };

  const handleDeleteCategory = async (id: string) => {
    await deleteDoc(doc(db, "categories", id));
    await loadCategories();
  };

  const handleConvertDrive = () => {
    if (!imageUrl.trim()) {
      setError("Paste a Google Drive link first.");
      return;
    }
    const converted = getDriveDirectLink(imageUrl.trim());
    if (!converted) {
      setError("That does not look like a Google Drive link.");
      return;
    }
    setError("");
    setImageUrl(converted);
    window.open("https://drive.google.com/", "_blank", "noopener,noreferrer");
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="border-b bg-white">
        <div className="mx-auto flex max-w-6xl items-center justify-between px-6 py-4">
          <div>
            <h1 className="text-2xl font-semibold">Admin Dashboard</h1>
            <p className="text-sm text-gray-500">Manage news and categories</p>
          </div>
          <button
            onClick={handleLogout}
            className="rounded-lg border border-gray-200 px-4 py-2 text-sm text-gray-700 hover:bg-gray-100"
          >
            Logout
          </button>
        </div>
      </header>

      <main className="mx-auto max-w-6xl px-6 py-8 space-y-8">
        {error && (
          <div className="rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-600">
            {error}
          </div>
        )}

        <section className="rounded-2xl bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold">Create News</h2>
          <form onSubmit={handleCreateNews} className="mt-4 grid gap-4">
            <input
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-indigo-500"
              placeholder="Title"
              value={title}
              onChange={(event) => setTitle(event.target.value)}
            />
            <input
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-indigo-500"
              placeholder="Summary"
              value={summary}
              onChange={(event) => setSummary(event.target.value)}
            />
            <textarea
              className="h-28 w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-indigo-500"
              placeholder="Content"
              value={content}
              onChange={(event) => setContent(event.target.value)}
            />
            <select
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-indigo-500"
              value={category}
              onChange={(event) => setCategory(event.target.value)}
            >
              <option value="">Select category</option>
              {categoryOptions.map((option) => (
                <option key={option.value} value={option.value}>
                  {option.label}
                </option>
              ))}
            </select>
            <div className="grid gap-2">
              <input
                className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-indigo-500"
                placeholder="Image URL (optional)"
                value={imageUrl}
                onChange={(event) => setImageUrl(event.target.value)}
              />
              <button
                type="button"
                onClick={handleConvertDrive}
                className="w-fit text-sm text-orange-600 hover:text-orange-700"
              >
                Convert Google Drive link to direct URL
              </button>
              <a
                href="https://postimages.org/"
                target="_blank"
                rel="noreferrer"
                className="text-sm text-indigo-600 hover:text-indigo-700"
              >
                Upload image and get URL (Postimages)
              </a>
            </div>
            <button
              type="submit"
              disabled={loading}
              className="rounded-lg bg-indigo-600 px-4 py-2 text-sm font-medium text-white hover:bg-indigo-700 disabled:opacity-60"
            >
              {loading ? "Saving..." : "Publish"}
            </button>
          </form>
        </section>

        <section className="rounded-2xl bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold">Latest News</h2>
          <div className="mt-4 space-y-3">
            {news.length === 0 ? (
              <p className="text-sm text-gray-500">No news yet.</p>
            ) : (
              news.map((item) => (
                <div
                  key={item.id}
                  className="flex items-center justify-between rounded-lg border border-gray-100 px-4 py-3"
                >
                  <div>
                    <p className="font-medium text-gray-900">{item.title}</p>
                    <p className="text-xs text-gray-500">{item.category}</p>
                  </div>
                  <button
                    onClick={() => handleDeleteNews(item.id)}
                    className="text-xs text-red-600 hover:text-red-700"
                  >
                    Delete
                  </button>
                </div>
              ))
            )}
          </div>
        </section>

        <section className="rounded-2xl bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold">Categories</h2>
          <div className="mt-4 flex flex-col gap-3 sm:flex-row">
            <input
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm outline-none focus:border-indigo-500"
              placeholder="Category name"
              value={categoryName}
              onChange={(event) => setCategoryName(event.target.value)}
            />
            <button
              type="button"
              onClick={handleCreateCategory}
              className="rounded-lg bg-gray-900 px-4 py-2 text-sm font-medium text-white hover:bg-gray-800"
            >
              Add
            </button>
          </div>
          <div className="mt-4 space-y-2">
            {categories.length === 0 ? (
              <p className="text-sm text-gray-500">No categories yet.</p>
            ) : (
              categories.map((item) => (
                <div
                  key={item.id}
                  className="flex items-center justify-between rounded-lg border border-gray-100 px-4 py-2"
                >
                  <div>
                    <p className="text-sm font-medium text-gray-900">
                      {item.name}
                    </p>
                    <p className="text-xs text-gray-500">{item.slug}</p>
                  </div>
                  <button
                    onClick={() => handleDeleteCategory(item.id)}
                    className="text-xs text-red-600 hover:text-red-700"
                  >
                    Delete
                  </button>
                </div>
              ))
            )}
          </div>
        </section>
      </main>
    </div>
  );
}
